import React from 'react';
import { Input } from '@linm-soft-org/linm-web-common-components';
import type { FormFieldLockResult } from '../form';
import { fieldPlaceholder } from '../form/FormMode';
import type { CustomerDto } from '../../services/master/models';
import { CustomerSearchField } from '../search';
import {
  CurrencyPairField,
  SalesVoucherHeaderSection,
  VoucherFormRow,
} from '../voucher';
import df from '../../styles/documentForm.module.css';

const CURRENCY_OPTIONS = [{ value: 'VND', label: 'VND - Việt Nam đồng' }];

export type HoaDonHeaderSectionProps = {
  testIdPrefix: string;
  headerExpanded: boolean;
  setHeaderExpanded: React.Dispatch<React.SetStateAction<boolean>>;
  fieldLock: FormFieldLockResult;
  invoiceDate: string;
  onInvoiceDateChange: (value: string) => void;
  invoiceCode: string;
  isNew: boolean;
  customerId: string;
  customerCode: string;
  customerName: string;
  onCustomerSelect: (c: CustomerDto) => void;
  onCustomerClear: () => void;
  taxCode: string;
  onTaxCodeChange: (value: string) => void;
  description: string;
  onDescriptionChange: (value: string) => void;
  shiftName?: string;
  cashierName?: string;
  legacyCode?: string;
};

/** Header 3 dòng — `voucher-form-header-lines.md` · `hoa-don-ban-header-compact-map.md` */
export const HoaDonHeaderSection: React.FC<HoaDonHeaderSectionProps> = ({
  testIdPrefix,
  headerExpanded,
  setHeaderExpanded,
  fieldLock,
  invoiceDate,
  onInvoiceDateChange,
  invoiceCode,
  isNew,
  customerId,
  customerCode,
  customerName,
  onCustomerSelect,
  onCustomerClear,
  taxCode,
  onTaxCodeChange,
  description,
  onDescriptionChange,
  shiftName,
  cashierName,
  legacyCode,
}) => {
  const {
    formMode,
    isStatusLocked,
    viewSectionClass,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    searchViewClass,
  } = fieldLock;
  const ph = (text: string) => fieldPlaceholder(formMode, text, { isStatusLocked });

  return (
    <SalesVoucherHeaderSection
      title="Thông tin hóa đơn"
      testIdPrefix={testIdPrefix}
      headerExpanded={headerExpanded}
      setHeaderExpanded={setHeaderExpanded}
      viewSectionClass={viewSectionClass}
    >
      {({ fieldClass, compactHideClass, formRowStyles }) => (
        <>
          <VoucherFormRow styles={formRowStyles}>
            <div
              className={fieldClass(compactHideClass(true))}
              data-testid={`${testIdPrefix}-field-invoiceDate`}
            >
              <label className={df.label}>Ngày hóa đơn *</label>
              <Input
                type="date"
                value={invoiceDate}
                onChange={e => onInvoiceDateChange(e.target.value)}
                {...(isNew ? fieldLockProps : staticFieldProps)}
              />
            </div>
            <div
              className={fieldClass(compactHideClass(false))}
              data-testid={`${testIdPrefix}-field-code`}
            >
              <label className={df.label}>Số hóa đơn</label>
              <Input
                value={invoiceCode}
                placeholder={ph('Tự động sinh')}
                {...staticFieldProps}
              />
            </div>
            <CurrencyPairField
              className={fieldClass(compactHideClass(false))}
              testIdPrefix={testIdPrefix}
              currencyCode="VND"
              exchangeRate={1}
              currencyOptions={CURRENCY_OPTIONS}
              staticFieldProps={staticFieldProps}
              selectDisabled={staticFieldProps.disabled}
            />
          </VoucherFormRow>

          <VoucherFormRow styles={formRowStyles}>
            <div
              className={fieldClass(df.spanCol2, compactHideClass(true))}
              data-testid={`${testIdPrefix}-field-customerId`}
            >
              <label className={df.label}>Khách hàng *</label>
              <CustomerSearchField
                customerId={customerId}
                customerCode={customerCode}
                customerName={customerName}
                onSelect={onCustomerSelect}
                onClear={onCustomerClear}
                disabled={searchDisabled}
                className={searchViewClass}
                placeholder={ph('Nhập mã hoặc tên khách hàng...')}
                testIdPrefix={`${testIdPrefix}-customer`}
              />
            </div>
            <div
              className={fieldClass(compactHideClass(false))}
              data-testid={`${testIdPrefix}-field-taxCode`}
            >
              <label className={df.label}>Mã số thuế</label>
              <Input
                value={taxCode}
                onChange={e => onTaxCodeChange(e.target.value)}
                placeholder={ph('Nhập mã số thuế...')}
                {...fieldLockProps}
              />
            </div>
          </VoucherFormRow>

          <VoucherFormRow styles={formRowStyles}>
            <div
              className={fieldClass(df.spanCol4, compactHideClass(false))}
              data-testid={`${testIdPrefix}-field-description`}
            >
              <label className={df.label}>Diễn giải</label>
              <Input
                value={description}
                onChange={e => onDescriptionChange(e.target.value)}
                placeholder={ph('Nhập diễn giải...')}
                {...fieldLockProps}
              />
            </div>
          </VoucherFormRow>

          {(shiftName || cashierName || legacyCode) ? (
            <VoucherFormRow styles={formRowStyles}>
              {legacyCode ? (
                <div
                  className={fieldClass(compactHideClass(false))}
                  data-testid={`${testIdPrefix}-field-legacyCode`}
                >
                  <label className={df.label}>Mã gốc</label>
                  <Input value={legacyCode} {...staticFieldProps} />
                </div>
              ) : null}
              {shiftName ? (
                <div
                  className={fieldClass(compactHideClass(false))}
                  data-testid={`${testIdPrefix}-field-shiftName`}
                >
                  <label className={df.label}>Ca bán</label>
                  <Input value={shiftName} {...staticFieldProps} />
                </div>
              ) : null}
              {cashierName ? (
                <div
                  className={fieldClass(compactHideClass(false))}
                  data-testid={`${testIdPrefix}-field-cashierName`}
                >
                  <label className={df.label}>Thu ngân</label>
                  <Input value={cashierName} {...staticFieldProps} />
                </div>
              ) : null}
            </VoucherFormRow>
          ) : null}
        </>
      )}
    </SalesVoucherHeaderSection>
  );
};
